const token = $input.first().json.headers['x-admin-token'];
if (!token) return [{json: {ok: 'false', error: 'No autorizado'}}];
try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  const parts = decoded.split('|');
  if (parts.length !== 3 || parts[2] !== 'CrackTesos2026_Admin_Token') return [{json: {ok: 'false', error: 'Token inválido'}}];
  const age = Date.now() - parseInt(parts[1]);
  if (age > 8 * 3600 * 1000) return [{json: {ok: 'false', error: 'Sesión expirada'}}];
  return [{json: {ok: 'true', email: parts[0]}}];
} catch(e) { return [{json: {ok: 'false', error: 'Token inválido'}}]; }

// Cada query puede ejecutarse múltiples veces por la cadena secuencial.
// Deduplicamos por clave primaria para obtener solo valores únicos.

const kpis = $('Query KPIs').first().json;

// Dedup por día
const dailyMap = {};
$('Query Diario').all().forEach(i => { const r = i.json; if (r.dia && !dailyMap[r.dia]) dailyMap[r.dia] = r; });
const daily = Object.values(dailyMap).sort((a,b) => String(a.dia).localeCompare(String(b.dia)));

// Dedup por agente
const agentsMap = {};
$('Query Agentes').all().forEach(i => { const r = i.json; if (r.agent_name && !agentsMap[r.agent_name]) agentsMap[r.agent_name] = r; });
const agents = Object.values(agentsMap).sort((a,b) => (b.goles||0)-(a.goles||0));

// Dedup por trivia_number
const triviasMap = {};
$('Query Trivias').all().forEach(i => { const r = i.json; if (r.trivia_number && !triviasMap[r.trivia_number]) triviasMap[r.trivia_number] = r; });
const trivias = Object.values(triviasMap).sort((a,b) => a.trivia_number - b.trivia_number);

// Dedup por trivia_number + speed_range
const speedMap = {};
$('Query Velocidad').all().forEach(i => { const r = i.json; const key = `${r.trivia_number}-${r.speed_range}`; if (r.speed_range && !speedMap[key]) speedMap[key] = r; });
const speed = Object.values(speedMap).sort((a,b) => a.trivia_number - b.trivia_number || a.speed_range - b.speed_range);

// Dedup por user_id para ranking
const rankingMap = {};
$('Query Ranking').all().forEach(i => { const r = i.json; if (r.name && !rankingMap[r.name]) rankingMap[r.name] = r; });
const ranking = Object.values(rankingMap).sort((a,b) => {
  const goalsDiff = (b.total_goals||0) - (a.total_goals||0);
  if (goalsDiff !== 0) return goalsDiff;
  return (parseFloat(a.avg_speed_seconds)||999999) - (parseFloat(b.avg_speed_seconds)||999999);
});

return [{json: {
  ok: true,
  generated_at: new Date().toLocaleString('es-CO', {timeZone: 'America/Bogota'}),
  kpis,
  daily,
  agents,
  trivias,
  speed,
  ranking
}}];
